118	void merge_sort_items(std::vector<int>& items_to_sort, int left, int right) {
119	    if (left < right) {
120	        int mid = left + (right - left) / 2;
121	        merge_sort_items(items_to_sort, left, mid);
122	        merge_sort_items(items_to_sort, mid + 1, right);
123	        merge_for_sort(items_to_sort, left, mid, right);
124	    }
125	}
