        int m = l + (r - l) / 2;
        ms(arr, l, m);
        ms(arr, m + 1, r);
        if (budget_done) return;

        int n1 = m - l + 1, n2 = r - m;
        std::vector<int> L(n1), R(n2);
        for (int i = 0; i < n1; i++) L[i] = arr[l + i];
        for (int i = 0; i < n2; i++) R[i] = arr[m + 1 + i];

        int i = 0, j = 0, k = l;
        while (i < n1 && j < n2) {
            if (budget_done) {
                while (i < n1) arr[k++] = L[i++];
                while (j < n2) arr[k++] = R[j++];
                return;
            }
            char c = compare_items(L[i], R[j]);
            if (c == '<' || c == '=') arr[k++] = L[i++];
            else arr[k++] = R[j++];
            if (queries_made >= sort_budget) budget_done = true;
        }
        while (i < n1) arr[k++] = L[i++];
        while (j < n2) arr[k++] = R[j++];
    };

    ms(sorted_items, 0, N - 1);

    // Assign proxy weights: use rank as proxy (simple linear spacing)
    // This avoids magnifying sort errors at the heavy end
    // rank k -> weight (k+1) so heaviest item gets weight N
    std::vector<double> proxy_w(N);
    for (int k = 0; k < N; k++) {
        int item = sorted_items[k];
        proxy_w[item] = (double)(k + 1);
    }

    // Greedy LPT assignment
    std::vector<int> assignment(N, 0);
    std::vector<double> group_sums(D, 0.0);

    std::vector<std::pair<double, int>> items_desc(N);
    for (int i = 0; i < N; i++) items_desc[i] = {-proxy_w[i], i};
    std::sort(items_desc.begin(), items_desc.end());

    for (int i = 0; i < N; i++) {
        int item = items_desc[i].second;
        int best_g = 0;
        for (int g = 1; g < D; g++) {
            if (group_sums[g] < group_sums[best_g]) best_g = g;
        }
        assignment[item] = best_g;
        group_sums[best_g] += proxy_w[item];
    }

    // SA refinement
    double total_sum = 0;
    for (int i = 0; i < N; i++) total_sum += proxy_w[i];
    double mean = total_sum / D;

    double sum_sq = 0;
    for (int g = 0; g < D; g++) sum_sq += group_sums[g] * group_sums[g];
    double current_var = sum_sq / D - mean * mean;

    double T = std::max(1.0, current_var * 0.3);
    std::uniform_real_distribution<double> unif(0.0, 1.0);
    std::uniform_int_distribution<int> item_dist(0, N - 1);
    std::uniform_int_distribution<int> group_dist(0, D - 1);

    int iters = 0;
    while (D > 1) {
        iters++;
        if (iters % 512 == 0) {
            auto now = std::chrono::steady_clock::now();
            if (std::chrono::duration_cast<std::chrono::milliseconds>(now - program_start_time) >= time_limit_ms)
                break;
            T *= 0.999;
            if (T < 1e-15) break;
        }

        bool do_swap = (rng() % 3 == 0);
        if (!do_swap) {
            int item = item_dist(rng);
            int old_g = assignment[item];
            int new_g = group_dist(rng);
            if (new_g == old_g) continue;

            double w = proxy_w[item];
            double new_s_old = group_sums[old_g] - w;
            double new_s_new = group_sums[new_g] + w;

            double new_sum_sq = sum_sq - group_sums[old_g]*group_sums[old_g] - group_sums[new_g]*group_sums[new_g]
                                       + new_s_old*new_s_old + new_s_new*new_s_new;
            double new_var = new_sum_sq / D - mean * mean;
            double delta = new_var - current_var;

            if (delta < 0 || (T > 1e-15 && unif(rng) < std::exp(-delta / T))) {
                current_var = new_var;
                sum_sq = new_sum_sq;
                group_sums[old_g] = new_s_old;
                group_sums[new_g] = new_s_new;
                assignment[item] = new_g;
            }
        } else {
            int i1 = item_dist(rng);
            int i2 = item_dist(rng);
            int g1 = assignment[i1], g2 = assignment[i2];
            if (g1 == g2) continue;

            double w1 = proxy_w[i1], w2 = proxy_w[i2];
            double new_s1 = group_sums[g1] - w1 + w2;
            double new_s2 = group_sums[g2] - w2 + w1;

            double new_sum_sq = sum_sq - group_sums[g1]*group_sums[g1] - group_sums[g2]*group_sums[g2]
                                       + new_s1*new_s1 + new_s2*new_s2;
            double new_var = new_sum_sq / D - mean * mean;
            double delta = new_var - current_var;

            if (delta < 0 || (T > 1e-15 && unif(rng) < std::exp(-delta / T))) {
                current_var = new_var;
                sum_sq = new_sum_sq;
                group_sums[g1] = new_s1;
                group_sums[g2] = new_s2;
                assignment[i1] = g2;
                assignment[i2] = g1;
            }
        }
    }

    // Exhaust remaining queries
    while (queries_made < Q) {
        int d1 = (queries_made % (N-1)) + 1;
        perform_query({0}, {d1});
    }

    for (int i = 0; i < N; i++) {
        std::cout << assignment[i] << (i == N-1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}
